    """Returns true if only one of the items in iterable is true."""
    count = 0
    for ii in iterable:
        if count > 1:
            return False  # Stop iterating if there is more then one.
        elif ii:  # If true.
            count += 1
            continue
    return True  # If went through loop sucessfully, return True.

